// Register.jsx - Clean
import React, { useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import s from './Auth.module.css';

export default function Register() {
  const nav = useNavigate();
  const { register } = useAuth();
  const [form, setForm] = useState({ username: '', email: '', password: '', confirm: '' });
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);

  const onSubmit = async e => {
    e.preventDefault();
    setError('');
    if (form.password !== form.confirm) return setError('Passwords do not match.');
    if (form.password.length < 6) return setError('Password must be at least 6 characters.');
    setLoading(true);
    try {
      await register(form.username, form.email, form.password);
      nav('/chat');
    } catch (err) {
      setError(err.response?.data?.detail || 'Registration failed.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className={s.page}>
      <div className={s.bg1} /><div className={s.bg2} />
      <button onClick={() => nav('/')} className={s.back}>← Back</button>
      <div className={s.card}>
        <div className={s.cardLogo}><img src="/logo.png" alt="Logo" style={{ width: 40 }} /></div>
        <h1 className={s.title}>Create account</h1>
        <p className={s.sub}>Join AWAL GPT</p>
        {error && <div className={s.err}>{error}</div>}
        <form onSubmit={onSubmit} className={s.form}>
          <div className={s.field}><label>Username</label><input className={s.input} type="text" value={form.username} onChange={e => setForm({...form, username: e.target.value})} required /></div>
          <div className={s.field}><label>Email</label><input className={s.input} type="email" value={form.email} onChange={e => setForm({...form, email: e.target.value})} required /></div>
          <div className={s.field}><label>Password</label><input className={s.input} type="password" value={form.password} onChange={e => setForm({...form, password: e.target.value})} required /></div>
          <div className={s.field}><label>Confirm</label><input className={s.input} type="password" value={form.confirm} onChange={e => setForm({...form, confirm: e.target.value})} required /></div>
          <button className={s.submit} disabled={loading}>{loading ? 'Creating...' : 'Create account →'}</button>
        </form>
        <p className={s.switch}>Have an account? <Link to="/login" className={s.link}>Sign in</Link></p>
      </div>
    </div>
  );
}
